def rotate_bits(number, shift_amount, bit_width, direction="left"):
    if not isinstance(number, int) or number < 0:
        raise ValueError("Number must be a non-negative integer.")
    if not isinstance(shift_amount, int) or shift_amount < 0:
        raise ValueError("Shift amount must be a non-negative integer.")
    if not isinstance(bit_width, int) or bit_width <= 0:
        raise ValueError("Bit width must be a positive integer.")

    mask = (1 << bit_width) - 1
    number &= mask

    shift_amount %= bit_width

    if shift_amount == 0:
        return number

    if direction == "left":
        return ((number << shift_amount) | (number >> (bit_width - shift_amount))) & mask
    elif direction == "right":
        return ((number >> shift_amount) | (number << (bit_width - shift_amount))) & mask
    else:
        raise ValueError("Direction must be 'left' or 'right'.")
